import { withDb } from "./db.mjs";

// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.
// Additionally, accounts/orders/invoices carry a `doc` JSONB column for the
// JSONB-store access pattern used by accounts.mjs and queries.mjs.
export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	// Add doc JSONB column to the three tables used by the application layer.
	// ALTER TABLE … ADD COLUMN IF NOT EXISTS is idempotent.
	for (const table of ["accounts", "orders", "invoices"]) {
		await client.query(
			`ALTER TABLE ${table} ADD COLUMN IF NOT EXISTS doc JSONB`
		);
	}
}

