// Add doc JSONB column to the three tables used by the application layer.
// ALTER TABLE … ADD COLUMN IF NOT EXISTS is idempotent.
for (const table of ["accounts", "orders", "invoices"]) {
	await client.query(
		`ALTER TABLE ${table} ADD COLUMN IF NOT EXISTS doc JSONB`
	);
}

// The application inserts only (pk, [fk], doc) into these tables and stores
// everything else in the JSONB doc.  Drop NOT NULL on all generated 3NF columns
// (except PKs) so those inserts don't violate constraints.
const dropNotNull = {
	accounts: ["name", "tier", "status", "created_at"],
	orders:   ["status", "total_cents", "currency", "created_at"],
	invoices: ["invoice_number", "amount_cents", "total_cents", "status",
	           "issued_at", "due_at"],
};
for (const [table, cols] of Object.entries(dropNotNull)) {
	for (const col of cols) {
		await client.query(
			`ALTER TABLE ${table} ALTER COLUMN ${col} DROP NOT NULL`
		);
	}
}
